code_example_1_basic.code:
#include <iostream>

namespace Converter {
    double celsiusToFahrenheit(double celsius) {
        return (celsius * 9.0 / 5.0) + 32.0;
    }
}

int main() {
    double inputTemp{0.0};
    std::cout << "Enter temperature in Celsius: ";
    if (std::cin >> inputTemp) {
        double result = Converter::celsiusToFahrenheit(inputTemp);
        std::cout << inputTemp << "C is " << result << "F\n";
    } else {
        std::cout << "Invalid numerical input!\n";
    }
    return 0;
}

code_example_2_practical.code:
#include <iostream>

namespace Avionics {
    inline namespace V1 {
        struct Sensor {
            int id{0};
            double reading{0.0};
        };

        void displaySensor(const Sensor& s) {
            std::cout << "[V1 Sensor] ID: " << s.id << " | Val: " << s.reading << "V\n";
        }
    }
}

int main() {
    Avionics::Sensor s1{101, 4.85};
    Avionics::displaySensor(s1);

    std::cout << "Change Sensor ID: ";
    int newId{0};
    if (!(std::cin >> newId)) {
        std::cout << "Stream error, resetting state.\n";
        std::cin.clear();
    } else {
        s1.id = newId;
        Avionics::displaySensor(s1);
    }
    return 0;
}

